INSERT INTO
    MCP_USER	(
                  USERID
                , PASSWORD
                , NAME
                , AUTH_CODE
                , EMAIL
                , POST
                , ADDRESS
                , ADDRESS_DTL
                , MOBILE_NO
                , BIRTHDAY
                , SYS_RDATE
                , LOGIN_COUNT
                , STATUS
                , USER_DIVISION
                , SMS_RCV_YN
                , EMAIL_RCV_YN
                , PIN
                , GENDER
                , PWD_CHG_DT
                , CLAUSE_PRI_AD_FLAG
                , PERSONAL_INFO_COLLECT_AGREE
                , OTHERS_TRNS_AGREE
                , AUTH_TEL_CODE
)
VALUES 		(
                  #{userId}
              , #{password}
              , #{name}
              , 'USER_ROLE'
              , #{email}
              , #{post}
              , #{address}
              , #{addressDtl}
              , #{mobileNo}
              , #{birthday}
              , SYSDATE
              , 0
              , '1'
              , '00'
              , #{agreeSMS}
              , #{agreeEmail}
              , #{pin}
              , #{gender}
              , SYSDATE
              , #{clausePriAdFlag}
              , #{personalInfoCollectAgree}
              , #{othersTrnsAgree}
              , #{authTelCode}
              )

