UPDATE MCP_USER SET
    SMS_RCV_YN = #{agreeSMS}
                  , EMAIL_RCV_YN = #{agreeEmail}
WHERE 1=1
  AND USERID = #{userId}

update MCP_MRKT_HIST
set END_DTTM = #{newEndDttm},
    RVISN_DTTM = sysdate,
    MKT_AGR_REFERER = #{mtkAgrReferer}
where GUBUN = #{gubun}
  and STRT_DTTM = #{strtDttm}
  and END_DTTM = #{endDttm}
  and USERID = #{userid}
